#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int x;
        scanf("%d", &x);
        int turns = 0;
        while (x % 101010 != 0) {
            if (x % 5 != 0) {
                printf("-1\n");
                break;
            }
            x *= 222;
            turns++;
            if (turns > 100) {
                printf("-1\n");
                break;
            }
        }
        if (x % 101010 == 0) {
            printf("%d\n", turns);
        }
    }
    return 0;
}

