        while (t-- > 0) {
            int x = sc.nextInt();
            int turns = 0;
            while (x % 101010 != 0) {
                if (x % 5 != 0) {
                    System.out.println(-1);
                    break;
                }
                x *= 222;
                turns++;
                if (turns > 100) {
                    System.out.println(-1);
                    break;
                }
            }
            if (x % 101010 == 0) {
                System.out.println(turns);
            }
        }
    }
}

